// apps/web/app/home/(user)/editor/_actions/generate-content.test.ts
import { generateContentAction } from './generate-content.action';
import { createMockUser } from '@/tests/factories/user';

describe('generateContentAction', () => {
  it('should validate prompt input with Zod schema', async () => {
    const user = createMockUser();
    const invalidInput = { prompt: '' }; // Empty prompt

    await expect(
      generateContentAction(invalidInput, user)
    ).rejects.toThrow('Prompt is required');
  });

  it('should generate content within time limit', async () => {
    const user = createMockUser();
    const input = { 
      prompt: 'Create a slide about AI benefits',
      slideId: 'slide-123'
    };

    const start = Date.now();
    const result = await generateContentAction(input, user);
    const duration = Date.now() - start;

    expect(result.success).toBe(true);
    expect(duration).toBeLessThan(5000); // 5 second limit
  });
});


// apps/web/app/home/(user)/editor/_actions/generate-content.action.ts
import { enhanceAction } from '@/lib/actions/enhance-action';
import { generateContentSchema } from './generate-content.schema';
import { generateWithPortkey } from '@/packages/ai-gateway';

export const generateContentAction = enhanceAction(
  async (input, user) => {
    // 1. Validate input
    const validated = generateContentSchema.parse(input);

    // 2. Check user permissions
    const canGenerate = await checkUserAIQuota(user.id);
    if (!canGenerate) {
      throw new Error('AI generation quota exceeded');
    }

    // 3. Generate content
    const content = await generateWithPortkey({
      prompt: validated.prompt,
      userId: user.id,
      context: validated.slideId
    });

    // 4. Track usage
    await trackAIUsage({
      userId: user.id,
      feature: 'slide-content-generation',
      tokens: content.usage.tokens
    });

    // 5. Return typed response
    return {
      success: true,
      content: content.text,
      usage: content.usage
    };
  },
  {
    auth: true,
    ratelimit: {
      key: 'ai-content-generation',
      limit: 10,
      window: '1h'
    }
  }
);

