// Prefer Server Components (default)
// apps/web/app/home/(user)/editor/_components/ContentGenerator.tsx

import { getCurrentUser } from '@/lib/auth/user';
import { ContentGeneratorClient } from './ContentGeneratorClient';

export async function ContentGenerator({ slideId }: Props) {
  const user = await getCurrentUser();
  const aiQuota = await getUserAIQuota(user.id);

  return (
    <ContentGeneratorClient
      userId={user.id}
      slideId={slideId}
      remainingQuota={aiQuota.remaining}
    />
  );
}

