step.example:

// packages/supabase/src/queries/slides.queries.ts

export async function updateSlideContent(
  client: SupabaseClient,
  slideId: string,
  content: string
) {
  // RLS automatically enforces user can only update their slides
  const { data, error } = await client
    .from('slides')
    .update({ content })
    .eq('id', slideId)
    .select()
    .single();

  if (error) {
    throw new SlideUpdateError(
      'Failed to update slide content',
      { cause: error }
    );
  }

  return data;
}


try {
  const result = await generateWithPortkey(options);
  return { success: true, data: result };
} catch (error) {
  // Handle specific error types
  if (error instanceof PortkeyQuotaError) {
    return {
      success: false,
      error: 'You have reached your AI generation limit for this period.'
    };
  }

  if (error instanceof PortkeyTimeoutError) {
    return {
      success: false,
      error: 'Content generation took too long. Please try again.'
    };
  }

  // Log unexpected errors
  console.error('Unexpected error in content generation:', error);

  // Return generic message
  return {
    success: false,
    error: 'Unable to generate content. Please try again later.'
  };
}


